// id       : op_302_01_27b
// 이름     : 컨테이너반입신고
// 경로     : 물류/작업실적/EDI/세관/컨테이너반입신고
// 작 성 자 : 최지수
// 작 업 일 : 2026-04-09
//==================================================================================================================
//현재일자
scwin.strToDate = $c.date.getServerDateTime($p, "yyyyMMdd");

//-------------------------------------------------------------------------
// 공통: 체크된 행의 반입일시 14자리 패딩 
//-------------------------------------------------------------------------
scwin.f_padCrryinoutDtm = function () {
  for (var i = 0; i < ds_cntrInDeclarInfo.getRowCount(); i++) {
    if (ds_cntrInDeclarInfo.getCellData(i, "chk") == 1) {
      var dtm = ds_cntrInDeclarInfo.getCellData(i, "crryinoutDtm");
      if (dtm.length < 14) {
        dtm = dtm + "00000000000000".substring(0, 14 - dtm.length);
        ds_cntrInDeclarInfo.setCellData(i, "crryinoutDtm", dtm);
      }
    }
  }
};

//-------------------------------------------------------------------------
// 공통: 체크된 행의 반입일시/반입유형/사고유형 필수값 검증
//-------------------------------------------------------------------------
scwin.f_validateCheckedRows = function () {
  for (var i = 0; i < ds_cntrInDeclarInfo.getRowCount(); i++) {
    if (ds_cntrInDeclarInfo.getCellData(i, "chk") == 1) {
      if (ds_cntrInDeclarInfo.getCellData(i, "crryinoutDtm") == "") {
        $c.gus.cfAlertMsg($p, MSG_CM_ERR_002, ["반입일시"]);
        return false;
      }
      if (ds_cntrInDeclarInfo.getCellData(i, "crryinoutPatternCd") == "") {
        $c.gus.cfAlertMsg($p, MSG_CM_ERR_002, ["반입유형코드"]);
        return false;
      }
      if (ds_cntrInDeclarInfo.getCellData(i, "accdPatternCd") == "") {
        $c.gus.cfAlertMsg($p, MSG_CM_ERR_002, ["사고유형코드"]);
        return false;
      }
      if (ds_cntrInDeclarInfo.getCellData(i, "crryinoutDtm").length < 14) {
        $c.gus.cfAlertMsg($p, "반입일시는 년/월/일/시/분/초 까지 입력하셔야 합니다.");
        return false;
      }
      // 날짜 유효성 검증 (ASIS covDateValidator 대응)
      if (!scwin.f_isValidDateTime(ds_cntrInDeclarInfo.getCellData(i, "crryinoutDtm"))) {
        $c.gus.cfAlertMsg($p, MSG_CM_ERR_038, ["반입일시"]);
        return false;
      }
    }
  }
  return true;
};

/* 날짜시간 유효성 검증 (YYYYMMDDHHmmss) */
scwin.f_isValidDateTime = function (val) {
  if (!val || val.length != 14) return false;
  var y = parseInt(val.substring(0, 4), 10);
  var m = parseInt(val.substring(4, 6), 10);
  var d = parseInt(val.substring(6, 8), 10);
  var hh = parseInt(val.substring(8, 10), 10);
  var mm = parseInt(val.substring(10, 12), 10);
  var ss = parseInt(val.substring(12, 14), 10);
  if (m < 1 || m > 12) return false;
  if (d < 1 || d > 31) return false;
  if (hh < 0 || hh > 23) return false;
  if (mm < 0 || mm > 59) return false;
  if (ss < 0 || ss > 59) return false;
  var dt = new Date(y, m - 1, d);
  if (dt.getFullYear() != y || dt.getMonth() != m - 1 || dt.getDate() != d) return false;
  return true;
};

//-------------------------------------------------------------------------
// 공통: 작업장 유효성 검증
//-------------------------------------------------------------------------
scwin.f_isValidWrkPl = function () {
  for (var i = 0; i < ds_wrkPlCd.getRowCount(); i++) {
    if (ds_wrkPlCd.getCellData(i, "cd") == dma_condition.get("wrkPlCd")) {
      return true;
    }
  }
  return false;
};
scwin.onpageload = function () {
  const codeOptions = [{
    grpCd: "OP133",
    compID: "gr_cntrInDeclarInfo:crryinoutPatternCd",
    opt: {
      "range": "1"
    }
  }, {
    grpCd: "OP132",
    compID: "gr_cntrInDeclarInfo:accdPatternCd",
    opt: {
      "range": "1"
    }
  }];
  $c.data.setCommonCode($p, codeOptions);
  ed_msn.setValue("");
  ed_hsn.setValue("");
  dma_condition.set("crryinoutClsCd", "I");
  $c.gus.cfDisableBtn($p, [btn_Save, btn_Trans, btn_Delete]);
  dma_wrkPlCd.set("grpCd", "SD151");
  dma_wrkPlCd.set("cd", "");
  dma_wrkPlCd.set("cdNm", "");
  $c.sbm.execute($p, sbm_wrkPlCd);
};
scwin.onUdcCompleted = function () {
  ed_crryinoutDtmFrom.setValue(scwin.strToDate);
  ed_crryinoutDtmTo.setValue(scwin.strToDate);
  ed_wrkPlCd.focus();
};

//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function () {
  //검색조건 필수 입력 체크
  if (!(await $c.gus.cfValidate($p, [tb_searchCondition]))) {
    return;
  }
  if (!$c.gus.cfIsAfterDate($p, ed_crryinoutDtmFrom.getValue(), ed_crryinoutDtmTo.getValue())) {
    $c.gus.cfAlertMsg($p, MSG_CM_ERR_039); // 시작일자를 종료일 이전으로 선택[입력]하여 주십시오.
    ed_crryinoutDtmFrom.focus();
    return;
  }
  if (declar_chk.getValue() == "1") {
    if (ed_cntrNo.getValue() == "" && ed_mrn.getValue() == "") {
      $c.gus.cfAlertMsg($p, "컨테이너,화물관리번호 중 하나는 입력해 주세요.");
      return false;
    }
  }
  if (declar_chk.getValue() == "1") {
    dma_condition.set("declarTrgtYn", 1);
  } else {
    dma_condition.set("declarTrgtYn", 0);
  }
  $c.sbm.execute($p, sbm_Retrieve);
};

//-------------------------------------------------------------------------
// 조회조건 필드 Clear
//-------------------------------------------------------------------------
scwin.f_FieldClear = function () {
  $c.gus.cfInitObjects($p, search_cond, null);
  ed_crryinoutDtmFrom.setValue(scwin.strToDate);
  ed_crryinoutDtmTo.setValue(scwin.strToDate);
};

//-------------------------------------------------------------------------
// 전송
//-------------------------------------------------------------------------
scwin.f_Trans = async function () {
  var count = 0;
  for (var i = 0; i < ds_cntrInDeclarInfo.getRowCount(); i++) {
    if (ds_cntrInDeclarInfo.getCellData(i, "chk") == 1 && ds_cntrInDeclarInfo.getCellData(i, "sndClsCd") == "4") {
      $c.gus.cfAlertMsg($p, "전송구분이 전송제외인 경우에는 전송을 하실수가 없습니다.");
      ds_cntrInDeclarInfo.setCellData(i, "chk", 0);
      return false;
    }
    if (ds_cntrInDeclarInfo.getCellData(i, "chk") == 1 && (ds_cntrInDeclarInfo.getCellData(i, "sndClsNm") == "전송대기" || ds_cntrInDeclarInfo.getCellData(i, "sndClsNm") == "전송완료")) {
      $c.gus.cfAlertMsg($p, "전송중에는 재전송을 하실수가 없습니다.");
      ds_cntrInDeclarInfo.setCellData(i, "chk", 0);
      return false;
    }
  }
  for (var i = 0; i < ds_cntrInDeclarInfo.getRowCount(); i++) {
    if (ds_cntrInDeclarInfo.getCellData(i, "chk") == 1) {
      ds_cntrInDeclarInfo.setCellData(i, "wrkPlCd", ed_wrkPlCd.getValue());
      count++;
    }
  }
  scwin.f_padCrryinoutDtm();
  if (!scwin.f_validateCheckedRows()) {
    return false;
  }
  if (!scwin.f_isValidWrkPl()) {
    $c.gus.cfAlertMsg($p, ed_wrkPlCd.getValue() + "작업장은 자료 전송이 불가능한 작업장입니다.");
    return false;
  }
  if (count == 0) {
    $c.gus.cfAlertMsg($p, "전송할 컨테이너번호를 선택해 주세요.");
    return false;
  }
  if (await $c.win.confirm($p, "전송하시겠습니까?")) {
    $c.sbm.execute($p, sbm_trans);
  }
};

//-------------------------------------------------------------------------
// 저장
//-------------------------------------------------------------------------
scwin.f_Save = async function () {
  var count = 0;
  for (var i = 0; i < ds_cntrInDeclarInfo.getRowCount(); i++) {
    if (ds_cntrInDeclarInfo.getCellData(i, "chk") == 1 && (ds_cntrInDeclarInfo.getCellData(i, "sndClsNm") == "전송완료" || ds_cntrInDeclarInfo.getCellData(i, "sndClsNm") == "" || ds_cntrInDeclarInfo.getCellData(i, "sndClsCd") == "4")) {
      $c.gus.cfAlertMsg($p, "전송구분이 전송완료/전송제외인 경우에는 저장을 하실수가 없습니다.");
      ds_cntrInDeclarInfo.setCellData(i, "chk", 0);
      return false;
    }
  }
  for (var i = 0; i < ds_cntrInDeclarInfo.getRowCount(); i++) {
    if (ds_cntrInDeclarInfo.getCellData(i, "chk") == 1) {
      count++;
    }
  }
  scwin.f_padCrryinoutDtm();
  if (!scwin.f_validateCheckedRows()) {
    return false;
  }
  if (!scwin.f_isValidWrkPl()) {
    $c.gus.cfAlertMsg($p, ed_wrkPlCd.getValue() + "작업장은 컨테이너 반입신고를 할 수 없는 작업장입니다.");
    return false;
  }
  dma_condition.set("delYn", 0);
  if (declar_chk.getValue() == "1") {
    for (var i = 0; i < ds_cntrInDeclarInfo.getRowCount(); i++) {
      if (ds_cntrInDeclarInfo.getCellData(i, "chk") == 1) {
        ds_cntrInDeclarInfo.setCellData(i, "rowStatus", "U");
      }
    }
  }
  if (ds_cntrInDeclarInfo.getModifiedIndex().length === 0) {
    $c.gus.cfAlertMsg($p, "변경된 사항이 없습니다.");
    return;
  }
  if (count == 0) {
    $c.gus.cfAlertMsg($p, "저장할 컨테이너번호를 선택해 주세요.");
    return false;
  }
  if (await $c.win.confirm($p, "저장하시겠습니까?")) {
    $c.sbm.execute($p, sbm_save);
  }
};

//-------------------------------------------------------------------------
// 삭제
//-------------------------------------------------------------------------
scwin.f_Delete = async function () {
  debugger;
  var count = 0;
  for (var i = 0; i < ds_cntrInDeclarInfo.getRowCount(); i++) {
    if (ds_cntrInDeclarInfo.getCellData(i, "chk") == 1) {
      count++;
    }
  }
  for (var i = 0; i < ds_cntrInDeclarInfo.getRowCount(); i++) {
    if (ds_cntrInDeclarInfo.getCellData(i, "chk") == 1 && ds_cntrInDeclarInfo.getCellData(i, "sndClsCd") != "3" && ds_cntrInDeclarInfo.getCellData(i, "sndClsCd") != "4") {
      $c.gus.cfAlertMsg($p, "삭제는 전송구분이 미전송/전송제외인 경우에만 가능합니다.");
      ds_cntrInDeclarInfo.setCellData(i, "chk", 0);
      return false;
    }
  }
  if (!scwin.f_isValidWrkPl()) {
    $c.gus.cfAlertMsg($p, ed_wrkPlCd.getValue() + "작업장은 자료 삭제가 불가능한 작업장입니다.");
    return false;
  }
  if (count == 0) {
    $c.gus.cfAlertMsg($p, "삭제할 컨테이너번호를 선택해 주세요.");
    return false;
  }
  for (var i = 0; i < ds_cntrInDeclarInfo.getRowCount(); i++) {
    if (ds_cntrInDeclarInfo.getCellData(i, "chk") == 1) {
      dma_condition.set("delYn", 1);
      ds_cntrInDeclarInfo.modifyRowStatus(i, "D");
    }
  }
  if (await $c.win.confirm($p, "삭제하시겠습니까?")) {
    $c.sbm.execute($p, sbm_delete);
  }
};

//-------------------------------------------------------------------------
// 오류 상세내역 조회 팝업
//-------------------------------------------------------------------------
scwin.f_errorPopUp = function (row) {
  //컨테이너 반입 오류시에도 오류상세내역 확인가능하게 수정
  var docCd = "";
  if (ds_cntrInDeclarInfo.getCellData(row, 'crryinoutPatternCd') == '19') {
    docCd = "355";
  } else {
    docCd = "5LA";
  }
  var declarNo = ds_cntrInDeclarInfo.getCellData(row, "crryinoutDeclarNo");
  var deg = 0;
  let data = {
    deg: deg,
    docCd: docCd,
    declarNo: declarNo
  };
  let opts = {
    id: "smpPop",
    popupName: "",
    modal: false,
    type: "browserPopup",
    width: 860,
    height: 580,
    title: ""
  };
  $c.win.openPopup($p, "/ui/ds/sd/odrmgnt/odrprewrk/sd_401_05_04p.xml", opts, data);
};

//-------------------------------------------------------------------------
//  전송구분에 따른 Total 
//-------------------------------------------------------------------------
scwin.f_sndClsTotal = function () {
  var v_send = 0; //전송 
  var v_unSend = 0; //미전송
  var v_acpt = 0; //접수 
  var v_error = 0; //오류 
  var v_transComplete = 0; //전송완료
  var v_forceAcpt = 0; //강제접수

  for (var i = 0; i < ds_cntrInDeclarInfo.getRowCount(); i++) {
    if (ds_cntrInDeclarInfo.getCellData(i, "sndClsNm") == "전송") v_send++;else if (ds_cntrInDeclarInfo.getCellData(i, "sndClsNm") == "미전송") v_unSend++;else if (ds_cntrInDeclarInfo.getCellData(i, "sndClsNm") == "접수") v_acpt++;else if (ds_cntrInDeclarInfo.getCellData(i, "sndClsNm") == "오류") v_error++;else if (ds_cntrInDeclarInfo.getCellData(i, "sndClsNm") == "전송완료") v_transComplete++;else if (ds_cntrInDeclarInfo.getCellData(i, "sndClsNm") == "강제접수") v_forceAcpt++;
  }
  send.setValue(v_send);
  unSend.setValue(v_unSend);
  acpt.setValue(v_acpt);
  error.setValue(v_error);
  transComplete.setValue(v_transComplete);
  forceAcpt.setValue(v_forceAcpt);
};

