//조회
scwin.sbm_Retrieve_submitdone = function (e) {
  if (e.responseJSON.resultDataSet[0].Code < 0) {
    $c.gus.cfAlertMsg($p, e.responseJSON.resultDataSet[0].Msg || "오류가 발생했습니다.");
    return;
  }
  grp_totalArea.setStyle("visibility", "visible");
  if (ds_cntrInDeclarInfo.getRowCount() == 0) {
    $c.gus.cfAlertMsg($p, MSG_CM_ERR_003); // 해당되는 자료가 존재하지 않습니다
  }
  totalRows.setValue(ds_cntrInDeclarInfo.getRowCount());
  scwin.f_sndClsTotal(); //전송 구분 별 Total

  for (var i = 0; i < ds_cntrInDeclarInfo.getRowCount(); i++) {
    if (declar_chk.getValue() == "1") {
      if (ds_cntrInDeclarInfo.getCellData(i, "dsmbrkBondZoneCd") == ds_cntrInDeclarInfo.getCellData(i, "bondZoneCd")) {
        ds_cntrInDeclarInfo.setCellData(i, "crryinoutPatternCd", "10");
      }
    }
    if (ds_cntrInDeclarInfo.getCellData(i, "accdPatternCd") == "") {
      ds_cntrInDeclarInfo.setCellData(i, "accdPatternCd", "OKY");
    }

    //경과일 폰트색 변경 (선조회 모드가 아닐 때만 적용)
    if (declar_chk.getValue() != "1") {
      if (Number(ds_cntrInDeclarInfo.getCellData(i, "arrowDt")) >= 3) {
        gr_cntrInDeclarInfo.setCellStyle(i, "arrowDt", "color", "red");
      } else {
        gr_cntrInDeclarInfo.setCellStyle(i, "arrowDt", "color", "black");
      }
    }
  }

  //전송구분이 오류이면 반입신고번호 폰트 변경
  for (var j = 0; j < ds_cntrInDeclarInfo.getRowCount(); j++) {
    if (ds_cntrInDeclarInfo.getCellData(j, "sndClsNm") == "오류") {
      gr_cntrInDeclarInfo.setCellStyle(j, "crryinoutDeclarNo", "textDecoration", "underline");
      gr_cntrInDeclarInfo.setCellStyle(j, "crryinoutDeclarNo", "cursor", "pointer");
    }
  }
  if (declar_chk.getValue() == "1") {
    $c.gus.cfDisableBtn($p, [btn_Trans, btn_Delete]);
  } else {
    $c.gus.cfEnableObjects($p, [btn_forced, btn_Save, btn_Trans, btn_Delete]);
  }
  ds_cntrInDeclarInfo.modifyAllStatus("R");
};

