//OnCloseUp
scwin.gr_cntrInDeclarInfo_oneditend = function (rowIndex, columnIndex, value) {
  var v_mrn = ed_mrn.getValue();
  var v_msn = ed_msn.getValue();
  var v_hsn = ed_hsn.getValue();
  if ($c.gus.cfIsNull($p, v_hsn)) {
    v_hsn = "0";
  }
  let colid = gr_cntrInDeclarInfo.getColumnID(columnIndex);
  if (colid == "crryinoutPatternCd") {
    for (var i = rowIndex + 1; i < ds_cntrInDeclarInfo.getRowCount(); i++) {
      if (ds_cntrInDeclarInfo.getCellData(i, "mrn") == v_mrn && ds_cntrInDeclarInfo.getCellData(i, "msn") == v_msn && ds_cntrInDeclarInfo.getCellData(i, "hsn") == v_hsn) {
        ds_cntrInDeclarInfo.setCellData(i, "crryinoutPatternCd", ds_cntrInDeclarInfo.getCellData(rowIndex, "crryinoutPatternCd"));
      }
    }
  }
};
scwin.gr_cntrInDeclarInfo_oncelldblclick = function (rowIndex, columnIndex, columnId) {
  let colid = gr_cntrInDeclarInfo.getColumnID(columnIndex);
  if (colid == "crryinoutDeclarNo") {
    if (ds_cntrInDeclarInfo.getCellData(rowIndex, "sndClsNm") == "오류") {
      scwin.f_errorPopUp(rowIndex);
    }
  }
  if (colid == "chk") {
    if (ds_cntrInDeclarInfo.getCellData(rowIndex, "sndClsCd") != "3" && ds_cntrInDeclarInfo.getCellData(rowIndex, "sndClsNm") != "오류" && ds_cntrInDeclarInfo.getCellData(rowIndex, "sndClsNm") != "전송완료" && ds_cntrInDeclarInfo.getCellData(rowIndex, "sndClsNm") != "" && ds_cntrInDeclarInfo.getCellData(rowIndex, "sndClsCd") != "4" && ds_cntrInDeclarInfo.getCellData(rowIndex, "sndClsCd") != "5") {
      $c.gus.cfAlertMsg($p, "전송구분이 전송완료/미전송/전송제외/오류/필수항목오류인 경우에만 선택하실수 있습니다.");
      ds_cntrInDeclarInfo.setCellData(rowIndex, "chk", 0);
      return false;
    }

    //같은 컨테이너번호 행 연동 체크
    for (var i = 0; i < ds_cntrInDeclarInfo.getRowCount(); i++) {
      if (ds_cntrInDeclarInfo.getCellData(rowIndex, "chk") == 1 && ds_cntrInDeclarInfo.getCellData(rowIndex, "cntrNo") == ds_cntrInDeclarInfo.getCellData(i, "cntrNo")) {
        ds_cntrInDeclarInfo.setCellData(i, "chk", 1);
      }
    }
  }
};

